class DocumentIndexer:
    def __init__(self, es_client: SecureElasticsearchClient):
        self.es = es_client.client
    
    def create_index(self, index_name: str, mappings: Dict = None, settings: Dict = None) -> bool:
        if self.es.indices.exists(index=index_name):
            print(f"Index '{index_name}' already exists")
            return False
        
        body = {}
        if settings:
            body['settings'] = settings
        if mappings:
            body['mappings'] = mappings
        
        self.es.indices.create(index=index_name, body=body if body else None)
        print(f"Index '{index_name}' created successfully")
        return True
    
    def index_document(self, index_name: str, document: Dict, doc_id: str = None) -> Dict:
        if doc_id:
            result = self.es.index(index=index_name, id=doc_id, document=document)
        else:
            result = self.es.index(index=index_name, document=document)
        
        return {
            'id': result['_id'],
            'index': result['_index'],
            'result': result['result']
        }
    
    def bulk_index_documents(self, index_name: str, documents: List[Dict]) -> Dict:
        from elasticsearch.helpers import bulk
        
        actions = [
            {
                '_index': index_name,
                '_source': doc
            }
            for doc in documents
        ]
        
        success, failed = bulk(self.es, actions, raise_on_error=False)
        
        return {
            'success': success,
            'failed': failed
        }
    
    def update_document(self, index_name: str, doc_id: str, updates: Dict) -> Dict:
        result = self.es.update(index=index_name, id=doc_id, doc=updates)
        return {
            'id': result['_id'],
            'result': result['result']
        }
    
    def delete_document(self, index_name: str, doc_id: str) -> Dict:
        result = self.es.delete(index=index_name, id=doc_id)
        return {
            'id': result['_id'],
            'result': result['result']
        }
    
    def get_document(self, index_name: str, doc_id: str) -> Optional[Dict]:
        try:
            result = self.es.get(index=index_name, id=doc_id)
            return result['_source']
        except NotFoundError:
            return None


